diff --git a/llvm/lib/Transforms/Scalar/Scalarizer.cpp b/llvm/lib/Transforms/Scalar/Scalarizer.cpp
index 2b27150112ad..18b8a8b04b5b 100644
--- a/llvm/lib/Transforms/Scalar/Scalarizer.cpp
+++ b/llvm/lib/Transforms/Scalar/Scalarizer.cpp
@@ -1084,14 +1084,16 @@ bool ScalarizerVisitor::visitExtractValueInst(ExtractValueInst &EVI) {
   if (!VS)
     return false;
   IRBuilder<> Builder(&EVI);
-  Scatterer Op0 = scatter(&EVI, Op, *VS);
   assert(!EVI.getIndices().empty() && "Make sure an index exists");
   // Note for our use case we only care about the top level index.
   unsigned Index = EVI.getIndices()[0];
-  for (unsigned OpIdx = 0; OpIdx < Op0.size(); ++OpIdx) {
-    Value *ResElem = Builder.CreateExtractValue(
-        Op0[OpIdx], Index, EVI.getName() + ".elem" + Twine(Index));
-    Res.push_back(ResElem);
+  // First extract the vector from the struct at the given index.
+  Value *Vec = Builder.CreateExtractValue(Op, Index,
+                                          Op->getName() + ".extract" + Twine(Index));
+  // Scatter the extracted vector.
+  Scatterer VecScatter = scatter(&EVI, Vec, *VS);
+  for (unsigned OpIdx = 0; OpIdx < VecScatter.size(); ++OpIdx) {
+    Res.push_back(VecScatter[OpIdx]);
   }

   gather(&EVI, Res, *VS);
